module fd32(
	input wire d_1,
	input wire clk_1,
	input wire clk_2,
	input wire clr,
	output reg q_1 
);
reg  in_1,in_2,in_3;
wire in_n;

always@(posedge clk_1)
  begin
	if(clr)
		begin		
		in_1 <= 1'b0;
		end	 
	else 
		in_1 <= d_1;
  end 

assign in_n = ~in_1;

always@(posedge clk_2)
  begin
	if(clr)
		begin
		in_2 <= 1'b0;
		in_3 <= 1'b0;
		end	 
	else
		in_2 <= in_n;            //不应将组合逻辑置于两个时钟域之间
		in_3 <= in_2;
		q_1 <= in_3;
  end 

endmodule

