module fd31(
	input wire a_1,
	input wire b_1,
	input wire sl_1,
	output reg  q_1
);
always@(sl_1 or a_1 or b_1)
	begin
		if(!sl) q_1 = a_1;
		else q_1 = b_1;
	end 
endmodule

