	input wire d_1,
	input wire d_2,
	input wire ce,
	input wire clk,
	input wire clr,
	output reg q_1 
);
mux2 mux2_1 (q_1,d_1,d_2,ce);//违反	
endmodule
primitive mux2(f,a,b,sel);
	output f;
	input a,b,sel;
	table
	//a b sel f
	  0 ? 0 : 0;
	  1 ? 0 : 1;
	  ? 0 1 : 0;
	  ? 1 1 : 1;
	  0 0 ? : 0;
	  1 1 ? : 1;
	endtable
endprimitive

